  className?: string;
}

// вФАвФАвФА Composant вФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФА

export function SearchFilter({
  searchValue = "",
  onSearchChange,
  placeholder = "Search...",
  filters = [],
  filterValues = {},
  onFiltersApply,
  onFiltersReset,
  sheetTitle = "Filters",
  className,
}: SearchFilterProps) {
  const [sheetOpen, setSheetOpen] = React.useState(false);
  // √Йtat local des filtres dans le Sheet (pas encore appliqu√©s)
  const [draft, setDraft] =
    React.useState<Record<string, string>>(filterValues);

  // Sync le draft depuis l'ext√©rieur quand le sheet s'ouvre
  React.useEffect(() => {
    if (sheetOpen) setDraft(filterValues);
  }, [sheetOpen, filterValues]);

  // Nombre de filtres actifs (non vides)
  const activeFilterCount = Object.values(filterValues).filter(Boolean).length;

  function handleApply() {
    onFiltersApply?.(draft);
    setSheetOpen(false);
  }

  function handleReset() {
    const empty = filters.reduce<Record<string, string>>((acc, f) => {
      acc[f.id] = "";
      return acc;
    }, {});
    setDraft(empty);
    onFiltersReset?.();
  }

  return (
    <>
      {/* вФАвФА Groupe input + bouton entonnoir вФАвФА */}
      <div
        data-slot="search-filter"
        className={cn(
          "flex h-8 items-center overflow-hidden rounded-lg border border-input bg-transparent transition-colors focus-within:border-ring",
          className,
        )}
      >
        <input
          type="text"
          value={searchValue}
          onChange={(e) => onSearchChange?.(e.target.value)}
          placeholder={placeholder}
          className="h-full min-w-0 flex-1 bg-transparent px-2.5 text-sm text-foreground placeholder:text-muted-foreground outline-none"
        />

        {/* S√©parateur vertical */}
        <div className="h-4 w-px shrink-0 bg-border" />

        {/* Bouton entonnoir */}
        <button
          type="button"
          onClick={() => setSheetOpen(true)}
          aria-label="Open filters"
          className={cn(
            "relative flex h-full items-center justify-center px-2.5 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground",
            activeFilterCount > 0 && "text-primary",
          )}
        >
          <HugeiconsIcon
            icon={ListFilterPlusIcon}
            size={16}
            strokeWidth={1.5}
          />
          {/* Pastille indicateur de filtres actifs */}
          {activeFilterCount > 0 && (
            <span className="absolute top-1 right-1 flex size-3.5 items-center justify-center rounded-full bg-primary text-[8px] font-bold text-primary-foreground">
              {activeFilterCount}
            </span>
          )}
        </button>
      </div>

      {/* вФАвФА Sheet de filtres вФАвФА */}
      <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
        <SheetContent side="right" className="flex w-full flex-col sm:max-w-sm">
          <SheetHeader>
            <SheetTitle>{sheetTitle}</SheetTitle>
            <SheetDescription className="sr-only">
              Filter results by selecting specific criteria.
            </SheetDescription>
          </SheetHeader>

          <Separator />

          {/* Champs de filtres */}
          <div className="flex flex-1 flex-col gap-5 overflow-y-auto px-4 py-2">
            {filters.length === 0 ? (
              <p className="text-sm text-muted-foreground">
                No filters configured.
              </p>
            ) : (
              filters.map((field) => (
                <div key={field.id} className="flex flex-col gap-2">
                  <Label htmlFor={`sf-filter-${field.id}`}>{field.label}</Label>
                  {field.render(draft[field.id] ?? "", (v) =>
                    setDraft((prev) => ({ ...prev, [field.id]: v })),
                  )}
                </div>
              ))
            )}
          </div>

          <Separator />

          {/* Footer */}
          <SheetFooter className="flex-row gap-2">
            <Button
              type="button"
              variant="outline"
              className="flex-1"
              onClick={handleReset}
            >
              Reset
            </Button>
            <SheetClose asChild>
              <Button type="button" className="flex-1" onClick={handleApply}>
                Apply
              </Button>
            </SheetClose>
          </SheetFooter>
        </SheetContent>
      </Sheet>
    </>
  );
}

